// Inline status icons for BTToast — colors are component-specific
// (Figma node 95:101) and hardcoded per CLAUDE.md §2.

import 'package:btech_ui/src/components/organisms/toast/toast.types.dart';
import 'package:flutter/material.dart';

/// Maps a typed toast to its 16×16 icon + brand colour.
///
/// Returns `null` for [BTToastType.default_] and [BTToastType.description]
/// — those variants render without a leading icon.
Widget? buildToastIcon(BTToastType type) {
  switch (type) {
    case BTToastType.success:
      return const Icon(Icons.check_circle, size: 16, color: _iconSuccess);
    case BTToastType.error:
      return const Icon(Icons.error, size: 16, color: _iconError);
    case BTToastType.warning:
      return const Icon(Icons.warning, size: 16, color: _iconWarning);
    case BTToastType.info:
      return const Icon(Icons.info, size: 16, color: _iconInfo);
    case BTToastType.default_:
    case BTToastType.description:
      return null;
  }
}

// component-specific icon palette — Figma node 95:101
const Color _iconSuccess = Color(0xFF0A632F);
const Color _iconError = Color(0xFF991515);
const Color _iconWarning = Color(0xFF8F760B);
const Color _iconInfo = Color(0xFF0F5E81);

// Barrel for the BTToast organism.

export 'toast.types.dart';
export 'toast_controller.dart';
export 'toast_widget.dart';

// BTToast types — Figma node 95:101.

import 'package:flutter/foundation.dart';

/// Visual variant of a toast.
///
/// - [default_] — title + close, no icon.
/// - [success] / [error] / [warning] / [info] — leading status icon + title.
/// - [description] — title + secondary description + optional action.
enum BTToastType { default_, success, error, warning, info, description }

/// On-screen placement of the [BTToaster] stack.
///
/// Mobile only supports vertical extremes — [top] and [bottom].
enum BTToastPosition { top, bottom }

/// Immutable data object describing one active toast.
@immutable
class BTToastItem {
  const BTToastItem({
    required this.id,
    required this.type,
    required this.title,
    this.description,
    this.actionLabel,
    this.onAction,
    this.duration = const Duration(seconds: 4),
  });

  final String id;
  final BTToastType type;
  final String title;
  final String? description;
  final String? actionLabel;
  final VoidCallback? onAction;

  /// How long the toast remains on screen before auto-dismissal.
  /// Use [Duration.zero] for a persistent toast that only closes on tap.
  final Duration duration;
}

/// BTToastController — imperative toast presenter.
///
/// Inserts a [BTToast] into the nearest [Overlay] for the given context,
/// animates it in with a fade + slide, and auto-dismisses after
/// [BTToastItem.duration]. Multiple toasts stack with 8 dp spacing.
///
/// ## Usage:
/// ```dart
/// BTToastController.show(
///   context,
///   const BTToastItem(
///     id: '1',
///     type: BTToastType.success,
///     title: 'Saved!',
///   ),
///   position: BTToastPosition.bottom,
/// );
/// ```
library;

import 'package:btech_ui/src/components/organisms/toast/toast.types.dart';
import 'package:btech_ui/src/components/organisms/toast/toast_widget.dart';
import 'package:flutter/material.dart';

/// Tracks an in-flight toast entry, exposes a [dismiss] hook for the
/// auto-dismiss timer + user taps.
class _BTToastEntry {
  _BTToastEntry({
    required this.id,
    required this.controller,
    required this.overlayEntry,
  });

  final String id;
  final AnimationController controller;
  final OverlayEntry overlayEntry;
}

/// Singleton controller. Manages the active toast stack per overlay.
class BTToastController {
  BTToastController._();

  static final BTToastController instance = BTToastController._();

  final List<_BTToastEntry> _entries = <_BTToastEntry>[];
  int _idSeq = 0;

  /// Pushes [item] onto the toast stack. Returns the generated id, which
  /// can be passed to [dismiss] to close the toast early.
  ///
  /// The [position] controls the vertical edge (top/bottom). Horizontal
  /// placement is always centred with 16 dp safe-area padding.
  static String show(
    BuildContext context,
    BTToastItem item, {
    BTToastPosition position = BTToastPosition.bottom,
  }) {
    return instance._show(context, item, position);
  }

  /// Dismisses the toast with the given [id] if it is still on screen.
  static void dismiss(String id) => instance._dismiss(id);

  String _show(
    BuildContext context,
    BTToastItem source,
    BTToastPosition position,
  ) {
    final overlay = Overlay.of(context);
    final navigator = Navigator.of(context, rootNavigator: true);
    final tickerProvider = navigator;

    final id = source.id.isNotEmpty ? source.id : 'bt-toast-${++_idSeq}';
    final item = source.id.isNotEmpty
        ? source
        : BTToastItem(
            id: id,
            type: source.type,
            title: source.title,
            description: source.description,
            actionLabel: source.actionLabel,
            onAction: source.onAction,
            duration: source.duration,
          );

    final controller = AnimationController(
      vsync: tickerProvider,
      duration: const Duration(milliseconds: 200),
      reverseDuration: const Duration(milliseconds: 150),
    );

    late final OverlayEntry entry;
    entry = OverlayEntry(
      builder: (ctx) => _ToastOverlay(
        controller: controller,
        item: item,
        position: position,
        index: _entries.indexWhere((e) => e.id == id),
        siblings: _entries,
        onClose: () => _dismiss(id),
      ),
    );

    final tracked = _BTToastEntry(
      id: id,
      controller: controller,
      overlayEntry: entry,
    );
    _entries.add(tracked);
    overlay.insert(entry);
    controller.forward();

    if (item.duration > Duration.zero) {
      Future<void>.delayed(item.duration, () => _dismiss(id));
    }
    return id;
  }

  void _dismiss(String id) {
    final i = _entries.indexWhere((e) => e.id == id);
    if (i < 0) return;
    final tracked = _entries[i];
    _entries.removeAt(i);
    tracked.controller.reverse().whenComplete(() {
      tracked.overlayEntry.remove();
      tracked.controller.dispose();
    });
  }
}

/// Renders a single toast inside the overlay with fade + slide animation.
///
/// Stacking is approximate — each toast is positioned independently with
/// its own offset based on the index when it was inserted.
class _ToastOverlay extends StatelessWidget {
  const _ToastOverlay({
    required this.controller,
    required this.item,
    required this.position,
    required this.index,
    required this.siblings,
    required this.onClose,
  });

  final AnimationController controller;
  final BTToastItem item;
  final BTToastPosition position;
  final int index;
  final List<dynamic> siblings;
  final VoidCallback onClose;

  @override
  Widget build(BuildContext context) {
    final isTop = position == BTToastPosition.top;
    const edgePadding = 16.0;
    const stackGap = 72.0; // toast height + 8 dp gap

    // Stack newest furthest from edge for "top" (newest at top of stack)
    // and newest closest to edge for "bottom" (sonner behaviour).
    final stackIndex = index < 0 ? siblings.length : index;
    final offset = edgePadding + stackIndex * stackGap;

    final slide = Tween<Offset>(
      begin: Offset(0, isTop ? -0.5 : 0.5),
      end: Offset.zero,
    ).animate(CurvedAnimation(parent: controller, curve: Curves.easeOut));
    final fade = CurvedAnimation(parent: controller, curve: Curves.easeOut);

    return Positioned(
      left: 0,
      right: 0,
      top: isTop ? offset : null,
      bottom: isTop ? null : offset,
      child: SafeArea(
        child: Align(
          alignment: Alignment.topCenter,
          child: FadeTransition(
            opacity: fade,
            child: SlideTransition(
              position: slide,
              child: BTToast(item: item, onClose: onClose),
            ),
          ),
        ),
      ),
    );
  }
}

/// BTToast — toast card widget (Flutter).
///
/// Figma source: node 95:101 (file WANr9drWYNYbMPuT2sMeHi).
///
/// Renders a 320 dp-wide card with status icon, title, optional
/// description, and a close button. The widget itself is stateless —
/// [BTToastController] owns the overlay/animation lifecycle.
///
/// ## Usage:
/// ```dart
/// BTToast(
///   item: BTToastItem(
///     id: '1',
///     type: BTToastType.success,
///     title: 'Saved!',
///   ),
///   onClose: () { /* ... */ },
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/organisms/toast/internal/toast_icons.dart';
import 'package:btech_ui/src/components/organisms/toast/toast.types.dart';
import 'package:flutter/material.dart';

// Arabic + Hebrew Unicode blocks — used to auto-flip the toast to RTL
// since the toast overlay sits outside the app's Directionality scope.
final RegExp _kRtlGlyph = RegExp(
  r'[֐-ۿݐ-ݿࢠ-ࣿיִ-﷿ﹰ-﻿]',
);

bool _isRtlText(String? a, String? b) {
  final s = '${a ?? ''} ${b ?? ''}';
  return _kRtlGlyph.hasMatch(s);
}

class BTToast extends StatelessWidget {
  const BTToast({
    required this.item,
    required this.onClose,
    super.key,
  });

  final BTToastItem item;
  final VoidCallback onClose;

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;
    final radius = context.btRadius;
    final family = BTTypography.fontFamily;

    final icon = buildToastIcon(item.type);
    final isDefault = item.type == BTToastType.default_;
    final isDescription = item.type == BTToastType.description;

    final isRtl = _isRtlText(item.title, item.description);

    return Directionality(
      textDirection: isRtl ? TextDirection.rtl : TextDirection.ltr,
      child: Material(
      color: Colors.transparent,
      child: Container(
        width: 320.0,
        padding: EdgeInsets.all(12.0),
        decoration: BoxDecoration(
          color: colors.bg.primary,
          border: Border.all(color: colors.border.primary),
          borderRadius: BorderRadius.circular(radius.md),
          boxShadow: const [
            BoxShadow(
              color: Color(0x0F000000),
              blurRadius: 4,
              offset: Offset(0, 2),
              spreadRadius: -2,
            ),
            BoxShadow(
              color: Color(0x1A000000),
              blurRadius: 6,
              offset: Offset(0, 4),
              spreadRadius: -1,
            ),
          ],
        ),
        child: Row(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            if (icon != null) ...[
              SizedBox(width: 16.0, height: 16.0, child: icon),
              SizedBox(width: 8.0),
            ],
            Expanded(
              child: isDefault
                  ? _buildDefaultBody(colors, family)
                  : isDescription
                      ? _buildDescriptionBody(colors, family)
                      : _buildTypedBody(colors, family),
            ),
          ],
        ),
      ),
    ),
    );
  }

  // ── Layout variants ────────────────────────────────────────────────

  Widget _buildDefaultBody(
    BTColorTheme colors,
    String family,
  ) {
    return Row(
      crossAxisAlignment: CrossAxisAlignment.center,
      children: [
        Expanded(child: _title(colors, family)),
        SizedBox(width: 8.0),
        _closeButton(colors),
      ],
    );
  }

  Widget _buildTypedBody(
    BTColorTheme colors,
    String family,
  ) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      mainAxisSize: MainAxisSize.min,
      children: [
        Row(
          crossAxisAlignment: CrossAxisAlignment.center,
          children: [
            Expanded(child: _title(colors, family)),
            SizedBox(width: 8.0),
            _closeButton(colors),
          ],
        ),
        if (item.description != null) ...[
          SizedBox(height: 2.0),
          _description(colors, family, item.description!),
        ],
      ],
    );
  }

  Widget _buildDescriptionBody(
    BTColorTheme colors,
    String family,
  ) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      mainAxisSize: MainAxisSize.min,
      children: [
        Row(
          crossAxisAlignment: CrossAxisAlignment.center,
          children: [
            Expanded(child: _title(colors, family)),
            SizedBox(width: 8.0),
            _closeButton(colors),
          ],
        ),
        if (item.description != null) ...[
          SizedBox(height: 2.0),
          _description(colors, family, item.description!),
        ],
        if (item.actionLabel != null) ...[
          SizedBox(height: 4.0),
          Align(
            alignment: AlignmentDirectional.centerStart,
            child: _actionButton(colors, family),
          ),
        ],
      ],
    );
  }

  // ── Primitives ─────────────────────────────────────────────────────

  Widget _title(BTColorTheme colors, String family) {
    return Text(
      item.title,
      style: TextStyle(
        fontFamily: family,
        fontSize: 14.0,
        fontWeight: FontWeight.w500,
        height: 16 / 14,
        color: colors.text.primary,
      ),
    );
  }

  Widget _description(BTColorTheme colors, String family, String text) {
    return Text(
      text,
      style: TextStyle(
        fontFamily: family,
        fontSize: 12.0,
        fontWeight: FontWeight.w500,
        height: 16 / 12,
        color: colors.text.secondary,
      ),
    );
  }

  Widget _closeButton(BTColorTheme colors) {
    return GestureDetector(
      onTap: onClose,
      behavior: HitTestBehavior.opaque,
      child: SizedBox(
        width: 16.0,
        height: 16.0,
        child: Icon(
          Icons.close,
          size: 16,
          color: colors.text.secondary,
        ),
      ),
    );
  }

  Widget _actionButton(BTColorTheme colors, String family) {
    return InkWell(
      onTap: item.onAction,
      borderRadius: BorderRadius.circular(6.0),
      child: Container(
        padding: EdgeInsets.all(8.0),
        decoration: BoxDecoration(
          border: Border.all(color: colors.border.primary),
          borderRadius: BorderRadius.circular(6.0),
        ),
        child: Text(
          item.actionLabel!,
          style: TextStyle(
            fontFamily: family,
            fontSize: 12.0,
            fontWeight: FontWeight.w500,
            height: 16 / 12,
            color: colors.text.primary,
          ),
        ),
      ),
    );
  }
}
